INSERT INTO lion_names(name, meaning) VALUES('Hareth', 'The fierce lion that digs the earth and is the guardian that protects, defends, and supports other lions.');
INSERT INTO lion_names(name, meaning) VALUES('Aklaaf', 'Lion with a big mane.');
INSERT INTO lion_names(name, meaning) VALUES('Haidar', 'A handsome and rather plump lion.');
INSERT INTO lion_names(name, meaning) VALUES('Abbas', 'The meanest and strongest lion in the pride! It is the lion that all others fear.');
INSERT INTO lion_names(name, meaning) VALUES('Furhud', 'Young lion cub that is good-looking and full-bodied.');
INSERT INTO lion_names(name, meaning) VALUES('Hamza', 'Denotes power and leadership.');
INSERT INTO lion_names(name, meaning) VALUES('Sarem', 'Strict, unrelenting and passionate - the lion with a big heart and big dreams.');
INSERT INTO lion_names(name, meaning) VALUES('Usayd', 'Usayd is little lion.');
INSERT INTO lion_names(name, meaning) VALUES('Feras', 'A strong lion that hunts all day long and manages to finish its prey whole.');
INSERT INTO lion_names(name, meaning) VALUES('Asrul', 'Unbeatable lion.');
INSERT INTO lion_names(name, meaning) VALUES('Layth', 'The brave lion. When this lion bares his teeth, do not fancy that the lion shows to you a smile.');
INSERT INTO lion_names(name, meaning) VALUES('Baqer', 'Inevitable, powerful lion.');
INSERT INTO lion_names(name, meaning) VALUES('Shibel', 'Its indicative of a powerful and successful breed, and a cub that can hunt on its own.');
INSERT INTO lion_names(name, meaning) VALUES('Bassel', 'A fierce lion that is always the first to sink its teeth and claws into any fight.');
INSERT INTO lion_names(name, meaning) VALUES('Muthafar', 'A lion dripping in blood.');
INSERT INTO lion_names(name, meaning) VALUES('Rebaal', 'A lion that has grown all its teeth and is used to describe bravery.');
INSERT INTO lion_names(name, meaning) VALUES('Dhergham', 'Denotes fearlessness. More specifically, it refers to a tough and fearless lion with magnificent sharp teeth.');
